var e=[{id:`L2_1`,type:`dialog`,speaker:`RYU_DANMACHI_NULL_NULL`,text:{KOREA:`어떤 과거를 지녔든 당신도 앞으로 나아가야만 하는 사정이 있는 거겠죠.`,JPN:`どんな過去があろうと、貴方も前に進まないといけない事情があるのでしょう。`,ENG:`No matter your past, you must move forward.`,TWN:`No matter your past, you must move forward.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RYU_DANMACHI_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RYU_DANMACHI_NULL_NULL`,text:{KOREA:`비록 이야기의 끝을 함께하지는 못하겠지만, 이 찰나의 순간만큼은 당신과 함께하겠습니다.`,JPN:`ずっとご一緒することはできませんが、この世界にいる間だけは貴方と一緒にいます。`,ENG:`I won't be there for the end of your story, but for this fleeting moment, I'll walk beside you.`,TWN:`I won't be there for the end of your story, but for this fleeting moment, I'll walk beside you.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RYU_DANMACHI_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};